/**
 * Server computes the SHA256 hash and byte size from the submitted content.
For `contentEncoding=text`, content is capped at 10 MB of UTF-8.
For `contentEncoding=base64`, the decoded payload is capped at 64 MB.
Larger requests return 413.

 * @summary Upload an evidence artifact
 */
export const getCreateArtifactUrl = (caseId: string) => {
  return `/api/cases/${caseId}/artifacts`;
};

export const createArtifact = async (
  caseId: string,
  createArtifactRequest: CreateArtifactRequest,
  options?: RequestInit,
): Promise<Artifact> => {
  return customFetch<Artifact>(getCreateArtifactUrl(caseId), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(createArtifactRequest),
  });
};

export const getCreateArtifactMutationOptions = <
  TError = ErrorType<
    BadRequestResponse | NotFoundResponse | PayloadTooLargeResponse
  >,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof createArtifact>>,
    TError,
    { caseId: string; data: BodyType<CreateArtifactRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof createArtifact>>,
  TError,
  { caseId: string; data: BodyType<CreateArtifactRequest> },
  TContext
> => {
  const mutationKey = ["createArtifact"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof createArtifact>>,
    { caseId: string; data: BodyType<CreateArtifactRequest> }
  > = (props) => {
    const { caseId, data } = props ?? {};

    return createArtifact(caseId, data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

